2096 |     function smartJSONParse(jsonString) {
2097 |         try {
2098 |             return JSON.parse(jsonString);
2099 |         } catch (e) {
2100 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
2101 |             let fixed = jsonString
2102 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
2103 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
2104 |                 // 2. Fix literal newlines inside strings (replace with \n)
2105 |                 .replace(/(\n)/g, (match, p1, offset) => {
2106 |                     // Only replace if we are likely inside a quoted string
2107 |                     const before = jsonString.slice(0, offset);
2108 |                     const quoteCount = (before.match(/"/g) || []).length;
2109 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
2110 |                 });
2111 | 
2112 |             try {
2113 |                 const cleanObj = JSON.parse(fixed);
2114 |                 document.getElementById('json-input').value = fixed;
2115 |                 if (typeof saveState === 'function') saveState();
2116 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
2117 |                 return cleanObj;
2118 |             } catch (e2) {
2119 |                 console.error("Robust fix failed:", e2);
2120 |                 throw e; // Throw original error for better debugging
2121 |             }
2122 |         }
2123 |     }
