2364 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2365 |     function applyLocalPatch(content, ops) {
2366 |         let lines = content.split('\n');
2367 |         let logs = [];
2368 |         let success = true;
2369 | 
2370 |         if (typeof ops === 'string') {
2371 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2372 |         }
2373 | 
2374 |         ops.forEach(op => {
2375 |             if (op.action === 'comment') return;
2376 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2377 |             
2378 |             if (op.action === 'replace_block') {
2379 |                 // Strategy 1: Exact String Match (Fastest)
2380 |                 const currentStr = lines.join('\n');
2381 |                 if (currentStr.includes(op.find_block)) {
2382 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2383 |                     logs.push('Exact match applied');
2384 |                     return;
2385 |                 }
2386 | 
2387 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2388 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2389 |                 if (searchLines.length === 0) return;
2390 | 
2391 |                 let matchStart = -1;
2392 |                 let matchEnd = -1;
2393 | 
2394 |                 // Scan file lines
2395 |                 for (let i = 0; i < lines.length; i++) {
2396 |                     // If first line matches (ignoring whitespace)
2397 |                     if (lines[i].trim() === searchLines[0]) {
2398 |                         // Check subsequent lines
2399 |                         let allMatch = true;
2400 |                         let fileOffset = 0;
2401 |                         let searchOffset = 1;
2402 |                         
2403 |                         while (searchOffset < searchLines.length) {
2404 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2405 |                             const nextFile = lines[i + fileOffset + 1].trim();
2406 |                             // Skip empty lines in file if they aren't in search block
2407 |                             if (nextFile === '') {
2408 |                                 fileOffset++;
2409 |                                 continue;
2410 |                             }
2411 |                             if (nextFile !== searchLines[searchOffset]) {
2412 |                                 allMatch = false;
2413 |                                 break;
2414 |                             }
2415 |                             fileOffset++;
2416 |                             searchOffset++;
2417 |                         }
2418 | 
2419 |                         if (allMatch) {
2420 |                             matchStart = i;
2421 |                             matchEnd = i + fileOffset;
2422 |                             break;
2423 |                         }
2424 |                     }
2425 |                 }
2426 | 
2427 |                 if (matchStart !== -1) {
2428 |                     // Replace the range of lines
2429 |                     const replacement = op.replace_with.split('\n');
2430 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2431 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2432 |                 } else {
2433 |                     success = false;
2434 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2435 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2436 |                 }
2437 |             }
2438 |         });
2439 |         return { content: lines.join('\n'), success, logs };
2440 |     }
