2444 |     async function runAutoFixLoop(name, code, errorList) {
2445 |         const status = document.getElementById('ef-status-msg');
2446 |         let currentCode = code;
2447 |         let currentErrors = errorList;
2448 | 
2449 |         // Fix one by one (recursive loop)
2450 |         async function fixNext(index) {
2451 |             if (index >= currentErrors.length) return true; // All initial errors processed
2452 | 
2453 |             const err = currentErrors[index];
2454 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
2455 |             status.style.color = "#eab308"; // Dev yellow
2456 | 
2457 |             try {
2458 |                 // 1. Get Patch from AI
2459 |                 const res = await fetch(CONFIG.funcUrl, { 
2460 |                     method: 'POST', 
2461 |                     headers: {'Content-Type': 'application/json'},
2462 |                     body: apiBody({ 
2463 |                         action: 'propose_syntax_fix', 
2464 |                         code: currentCode, 
2465 |                         error: err 
2466 |                     })
2467 |                 });
2468 |                 const data = await res.json();
2469 |                 const ops = data.operations;
2470 | 
2471 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
2472 | 
2473 |                 // 2. Apply Patch Locally
2474 |                 const patchResult = applyLocalPatch(currentCode, ops);
2475 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
2476 | 
2477 |                 currentCode = patchResult.content;
2478 |                 document.getElementById('ef-code').value = currentCode; // Update UI
2479 | 
2480 |                 // 3. Re-Validate
2481 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
2482 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
2483 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
2484 |                 });
2485 |                 const scanData = await scanRes.json();
2486 | 
2487 |                 if (scanData.valid) {
2488 |                     status.innerText = "✅ Syntax Fixed!";
2489 |                     return true;
2490 |                 } else {
2491 |                     // If errors remain, update list and Prompt user
2492 |                     currentErrors = scanData.errors;
2493 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
2494 |                         // Recursively fix the *new* first error (since layout changed)
2495 |                         return await fixNext(0);
2496 |                     } else {
2497 |                         return false;
2498 |                     }
2499 |                 }
2500 | 
2501 |             } catch (e) {
2502 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
2503 |                     return await fixNext(index);
2504 |                 } else {
2505 |                     return false;
2506 |                 }
2507 |             }
2508 |         }
2509 | 
2510 |         return await fixNext(0);
2511 |     }
