5512 |     function formatBytes(bytes) {
5513 |         if (!bytes) return '0 B';
5514 |         const k = 1024;
5515 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5516 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5517 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5518 |     }
