5520 |     function timeAgo(dateString) {
5521 |         const date = new Date(dateString);
5522 |         const now = new Date();
5523 |         const seconds = Math.floor((now - date) / 1000);
5524 |         if (seconds < 10) return 'just now';
5525 |         if (seconds < 60) return seconds + 's ago';
5526 |         const minutes = Math.floor(seconds / 60);
5527 |         if (minutes < 60) return minutes + 'm ago';
5528 |         const hours = Math.floor(minutes / 60);
5529 |         if (hours < 24) return hours + 'h ago';
5530 |         return date.toLocaleDateString();
5531 |     }
