5759 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
5760 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
5761 |         
5762 |         const navItems = document.querySelectorAll('.nav-item');
5763 |         switchTab(tabId, navItems[navIndex]);
5764 | 
5765 |         const scrollContainer = document.querySelector('.main-view');
5766 |         let retryCount = 0;
5767 |         const MAX_RETRIES = 5;
5768 | 
5769 |         const attemptNavigation = async () => {
5770 |             const element = document.querySelector(selector);
5771 |             
5772 |             if (element) {
5773 |                 console.log("[DeepJump] Element found. Scrolling...");
5774 |                 
5775 |                 // Wait for any tab transition animations
5776 |                 await new Promise(r => setTimeout(r, 300));
5777 | 
5778 |                 let offsetTop = 0;
5779 |                 let curr = element;
5780 |                 while (curr && curr !== scrollContainer) {
5781 |                     offsetTop += curr.offsetTop;
5782 |                     curr = curr.offsetParent;
5783 |                 }
5784 | 
5785 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5786 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5787 | 
5788 |                 // Visual Highlight
5789 |                 element.style.transition = 'all 0.5s ease';
5790 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
5791 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
5792 |                 setTimeout(() => {
5793 |                     element.style.backgroundColor = '';
5794 |                     element.style.boxShadow = '';
5795 |                 }, 3000);
5796 |                 
5797 |                 console.groupEnd();
5798 |                 return true;
5799 |             }
5800 | 
5801 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5802 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5803 |                 retryCount++;
5804 |                 showGlobalToast("🔍 Searching deeper...");
5805 |                 
5806 |                 await loadMoreFn(); 
5807 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5808 |                 return attemptNavigation();
5809 |             }
5810 | 
5811 |             console.error("[DeepJump] Failed: Element not found after retries.");
5812 |             showGlobalToast("Entry not found in recent history.", true);
5813 |             console.groupEnd();
5814 |             return false;
5815 |         };
5816 | 
5817 |         setTimeout(attemptNavigation, 100);
5818 |     }
