7669 |         const idsToDelete = checkboxes.map(cb => cb.value);
7670 |         
7671 |         // Find the oldest record among the selection to determine rollback target
7672 |         // dbHistory is sorted newest -> oldest
7673 |         let oldestSelectedIndex = -1;
7674 |         checkboxes.forEach(cb => {
7675 |             const idx = dbHistory.findIndex(h => String(h.id) === String(cb.value));
7676 |             if (idx > oldestSelectedIndex) oldestSelectedIndex = idx;
7677 |         });
7678 | 
7679 |         // The target is the first record older than our selection that isn't also being deleted
7680 |         let rollbackTarget = null;
7681 |         for (let i = oldestSelectedIndex + 1; i < dbHistory.length; i++) {
7682 |             if (!idsToDelete.includes(String(dbHistory[i].id))) {
7683 |                 rollbackTarget = dbHistory[i];
7684 |                 break;
7685 |             }
7686 |         }
7687 | 
7688 |         let msg = `Delete ${checkboxes.length} selected records?`;
7689 |         if (rollbackTarget) {
7690 |             msg += `\n\n⚠️ This will ROLLBACK your GitHub repository to: "${rollbackTarget.title}"`;
7691 |         }
7692 | 
7693 |         if (!confirm(msg)) return;
7694 | 
7695 |         showGlobalToast("Batch Deleting & Rolling back...");
7696 | 
7697 |         // 1. Perform Rollback
7698 |         if (rollbackTarget) {
7699 |             await fetch(CONFIG.funcUrl, {
7700 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7701 |                 body: apiBody({ action: 'rollback', ref_sha: rollbackTarget.sha })
7702 |             });
