7707 |             fetch(CONFIG.funcUrl, {
7708 |                 method: 'POST', headers: {'Content-Type': 'application/json'},
7709 |                 body: apiBody({ action: 'delete_history', id: id })
7710 |             })
7711 |         ));
7712 | 
7713 |         historyOffset = 0;
7714 |         logOffset = 0;
7715 |         fetchState(true);
7716 |         fetchFileList();
7717 |         if (rollbackTarget) setTimeout(() => bundleAndPreview(null), 1000);
