8649 |     function extractTableNames(sql) {
8650 |         if (!sql) return [];
8651 |         const tables = [];
8652 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8653 |         
8654 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8655 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8656 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8657 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8658 | 
8659 |         let match;
8660 |         while ((match = fromRegex.exec(sql)) !== null) {
8661 |             const name = match[1];
8662 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8663 |                 tables.push(name);
8664 |             }
8665 |         }
8666 |         
8667 |         while ((match = metaRegex.exec(sql)) !== null) {
8668 |             const name = match[1];
8669 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8670 |                 tables.push(name);
8671 |             }
8672 |         }
8673 | 
8674 |         return tables;
8675 |     }
8676 | 
8677 |     function convertToCSV(resultObj) {
8678 |         const data = resultObj.data || [];
8679 |         if (!data.length) return '';
8680 |         
8681 |         const tables = extractTableNames(resultObj.sql);
8682 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8683 | 
8684 |         const headers = Object.keys(data[0]);
8685 |         const rows = data.map(row => 
8686 |             headers.map(header => {
8687 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8688 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8689 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8690 |             }).join(',')
8691 |         );
8692 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8693 |     }
