function handlePressStart(e, pkg, isDock, isHome) {
    // Add visual pressing state
    e.currentTarget.classList.add('is-pressing');

    longPressTimer = setTimeout(() => {
        // Remove pressing state if menu opens
        const items = document.querySelectorAll('.app-item');
        items.forEach(el => el.classList.remove('is-pressing'));

        showContextMenu(e.touches[0].clientX, e.touches[0].clientY, pkg, isDock, isHome);
    }, 600);
}

