function addToHome(pkg) {
    if (dockPkgs.length < 4 && !dockPkgs.includes(pkg)) {
        dockPkgs.push(pkg);
        localStorage.setItem('cortex_dock', JSON.stringify(dockPkgs));
    } else {
        // Add to first page that has space (max 24 per page to keep it clean)
        let added = false;
        for (let page of homePages) {
            if (page.length < 24 && !page.includes(pkg) && !dockPkgs.includes(pkg)) {
                page.push(pkg);
                added = true; break;
            }
        }
        if (!added) homePages.push([pkg]);
        localStorage.setItem('cortex_home_pages', JSON.stringify(homePages));
    }
    renderAll(allApps);
    closeMenu();
}

function removeFromHome(pkg, pageIdx) {
